class Order:
    def __init__(self, items_in_cart, delivery_speed, delivery_address):
        self.items_in_cart = items_in_cart
        self.delivery_speed = delivery_speed
        self.delivery_address = delivery_address

    def add_item(self, item):
        self.items_in_cart.append(item)

    def display_order_details(self):
        print(f"Items in Cart: {self.items_in_cart}")
        print(f"Delivery Speed: {self.delivery_speed}")
        print(f"Delivery Address: {self.delivery_address}")

class PrimeOrder(Order):
    def __init__(self, items_in_cart, delivery_speed, delivery_address, prime_discount):
        super().__init__(items_in_cart, delivery_speed, delivery_address)
        self.prime_discount = prime_discount

    def apply_prime_discount(self, total_bill):
        return total_bill * (1 - self.prime_discount / 100)

class GroupOrder(PrimeOrder):
    def __init__(self, items_in_cart, delivery_speed, delivery_address, prime_discount, group_discount):
        super().__init__(items_in_cart, delivery_speed, delivery_address, prime_discount)
        self.group_discount = group_discount

    def apply_group_discount(self, total_bill):
        return total_bill * (1 - self.group_discount / 100)

