def default_test():
    order = Order(["Book", "Laptop"], "Two-Day", "123 Main Street")
    prime_order = PrimeOrder(["Headphones", "Charger"], "One-Day", "456 Elm Street", 10)
    group_order = GroupOrder(["T-shirts", "Jeans"], "Same-Day", "789 Maple Avenue", 10, 5)
    final_bill = group_order.apply_group_discount(prime_order.apply_prime_discount(100))
    print(final_bill)
